#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>
#include <math.h>
#include <float.h>

#include "kmeans.h"

#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

extern double wtime(void);

__global__ void find_nearest_point_kernel(float *features, int nfeatures, int npoints,
                                          float *clusters, int nclusters,
                                          int *membership, float *delta_ptr) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= npoints) return;

    float min_dist = FLT_MAX;
    int index = 0;

    for (int c = 0; c < nclusters; c++) {
        float dist = 0.0f;
        for (int d = 0; d < nfeatures; d++) {
            float diff = features[i * nfeatures + d] - clusters[c * nfeatures + d];
            dist += diff * diff;
        }
        if (dist < min_dist) {
            min_dist = dist;
            index = c;
        }
    }

    if (index != membership[i]) {
        *delta_ptr += 1.0f;
    }
    membership[i] = index;
}

__global__ void accumulate_centers_kernel(float *features, int nfeatures, int npoints,
                                          int *membership, int nclusters,
                                          int *counts, float *sums) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= npoints) return;

    int cluster_id = membership[i];
    counts[cluster_id]++;
    for (int d = 0; d < nfeatures; d++) {
        sums[cluster_id * nfeatures + d] += features[i * nfeatures + d];
    }
}

__global__ void update_centers_kernel(float *clusters, int nfeatures, int nclusters,
                                      int *counts, float *sums) {
    int c = blockIdx.x * blockDim.x + threadIdx.x;
    if (c >= nclusters) return;

    if (counts[c] > 0) {
        for (int d = 0; d < nfeatures; d++) {
            clusters[c * nfeatures + d] = sums[c * nfeatures + d] / counts[c];
        }
    }
}

int cluster(int numObjects,
            int numAttributes,
            float **attributes,
            int nclusters,
            float threshold,
            float ***cluster_centres)
{
    int *membership;
    float **tmp_cluster_centres;
    float *d_features;
    float *d_clusters;
    int *d_membership;
    float *d_delta;
    int *d_counts;
    float *d_sums;
    float delta;

    membership = (int*) malloc(numObjects * sizeof(int));

    srand(7);

    // Allocate GPU memory
    cudaMalloc(&d_features, numObjects * numAttributes * sizeof(float));
    cudaMalloc(&d_clusters, nclusters * numAttributes * sizeof(float));
    cudaMalloc(&d_membership, numObjects * sizeof(int));
    cudaMalloc(&d_delta, sizeof(float));
    cudaMalloc(&d_counts, nclusters * sizeof(int));
    cudaMalloc(&d_sums, nclusters * numAttributes * sizeof(float));

    // Copy input data to GPU
    float *flat_attributes = attributes[0];
    cudaMemcpy(d_features, flat_attributes, numObjects * numAttributes * sizeof(float), cudaMemcpyHostToDevice);

    // Initialize clusters on GPU (copy first nclusters points)
    float *init_clusters = (float*)malloc(nclusters * numAttributes * sizeof(float));
    for (int i = 0; i < nclusters; i++) {
        memcpy(&init_clusters[i * numAttributes], attributes[i], numAttributes * sizeof(float));
    }
    cudaMemcpy(d_clusters, init_clusters, nclusters * numAttributes * sizeof(float), cudaMemcpyHostToDevice);
    free(init_clusters);

    // Initialize membership to -1
    int *init_membership = (int*)malloc(numObjects * sizeof(int));
    for (int i = 0; i < numObjects; i++) init_membership[i] = -1;
    cudaMemcpy(d_membership, init_membership, numObjects * sizeof(int), cudaMemcpyHostToDevice);
    free(init_membership);

    int block_size = 256;
    int num_blocks_points = (numObjects + block_size - 1) / block_size;
    int num_blocks_clusters = (nclusters + block_size - 1) / block_size;

    int loop = 0;
    do {
        delta = 0.0f;
        cudaMemcpy(d_delta, &delta, sizeof(float), cudaMemcpyHostToDevice);

        // Reset counts and sums
        cudaMemset(d_counts, 0, nclusters * sizeof(int));
        cudaMemset(d_sums, 0, nclusters * numAttributes * sizeof(float));

        // Find nearest point
        find_nearest_point_kernel<<<num_blocks_points, block_size>>>(d_features, numAttributes, numObjects,
                                                                     d_clusters, nclusters,
                                                                     d_membership, d_delta);

        // Accumulate new centers
        accumulate_centers_kernel<<<num_blocks_points, block_size>>>(d_features, numAttributes, numObjects,
                                                                     d_membership, nclusters,
                                                                     d_counts, d_sums);

        // Update centers
        update_centers_kernel<<<num_blocks_clusters, block_size>>>(d_clusters, numAttributes, nclusters,
                                                                   d_counts, d_sums);

        cudaMemcpy(&delta, d_delta, sizeof(float), cudaMemcpyDeviceToHost);

    } while (delta > threshold && loop++ < 500);

    // Copy final clusters back to host
    float *final_clusters = (float*)malloc(nclusters * numAttributes * sizeof(float));
    cudaMemcpy(final_clusters, d_clusters, nclusters * numAttributes * sizeof(float), cudaMemcpyDeviceToHost);

    // Reconstruct 2D array structure
    tmp_cluster_centres = (float**) malloc(nclusters * sizeof(float*));
    tmp_cluster_centres[0] = final_clusters;
    for (int i = 1; i < nclusters; i++) {
        tmp_cluster_centres[i] = tmp_cluster_centres[i-1] + numAttributes;
    }

    if (*cluster_centres) {
        free((*cluster_centres)[0]);
        free(*cluster_centres);
    }
    *cluster_centres = tmp_cluster_centres;

    // Cleanup GPU memory
    cudaFree(d_features);
    cudaFree(d_clusters);
    cudaFree(d_membership);
    cudaFree(d_delta);
    cudaFree(d_counts);
    cudaFree(d_sums);

    free(membership);

    return 0;
}

